  }
  });
} catch (e) {
  // Notification failure should not break the workflow
}
return items;

// Use pre-extracted grant data from scanner
const body = $input.first().json.body;
const grantData = body.grantData || {};

return [{ 
  json: { 
    grantContent: `
Grant Title: ${grantData.title || 'Not specified'}
Agency: ${grantData.agency || 'Not specified'}
Award Range: ${grantData.awardRange || 'Not specified'}
Deadline: ${grantData.deadline || 'Not specified'}
Open Date: ${grantData.openDate || 'Not specified'}
Description: ${grantData.description || 'No description provided'}
Source: ${grantData.source || 'Grant Scanner'}
Matched Keywords: ${grantData.matchedKeywords || 'None'}
`.trim(),
    grantid: body.grantId || body.grantid || '',
    sourceUrl: body.url || grantData.url || '',
    sourceType: 'scanner',
    fetchedAt: new Date().toISOString(),
    originalGrantData: grantData
  } 
}];

// Return result for rejected grants (RED score)
const data = $('Format Analysis Response').first().json;

return [{
  json: {
    success: true,
    eligibility: data.eligibility,
    grantInfo: data.grantInfo,
    categories: data.categories,
    concerns: data.concerns,
    recommendations: data.recommendations,
    addedToTracker: false,
    rejectionReason: 'Grant did not pass eligibility screening (RED score)',
    source: data.source
  }
}];

// Extract text content from HTML
const item = $input.first();
const html = item.json.data || item.json.body || '';
const url = $('Webhook Trigger').first().json.body.url || '';

if (!html || typeof html !== 'string') {
  return [{ json: { error: true, message: 'Failed to fetch grant page', url: url } }];
}

// Remove scripts, styles, and extract text
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

// Limit to ~15000 chars for AI processing
if (text.length > 15000) {
  text = text.substring(0, 15000) + '... [truncated]';
}

return [{ 
  json: { 
    grantContent: text,
    sourceUrl: url,
    sourceType: 'url',
    fetchedAt: new Date().toISOString()
  } 
}];

// Handle document input (base64 PDF or text)
const item = $input.first();
const body = item.json.body || {};

let content = '';
let filename = body.filename || 'document';

if (body.document) {
  if (body.documentText) {
    content = body.documentText;
  } else {
    content = Buffer.from(body.document, 'base64').toString('utf-8');
  }
} else if (body.text) {
  content = body.text;
}

if (!content || content.length < 50) {
  return [{ json: { error: true, message: 'No valid document content provided' } }];
}

if (content.length > 15000) {
  content = content.substring(0, 15000) + '... [truncated]';
}

return [{ 
  json: { 
    grantContent: content,
    sourceUrl: filename,
    sourceType: 'document',
    fetchedAt: new Date().toISOString()
  } 
}];

// Grant Categories for Eligibility Matching
const eligibilityCriteria = {
  categories: [
    {
      name: "Core Program Grants",
      priority: "TOP",
      focus: "Direct services for youth aging out of foster care & seniors",
      awardMin: 15000,
      awardMax: 75000,
      useFor: ["Clothing & essentials distribution", "Hygiene kits & transition supplies", "Senior engagement & dignity initiatives"],
      bestFunders: ["Community foundations", "Family foundations", "Local corporate foundations"],
      keywords: ["dignity", "stability", "equity", "transition support", "foster youth", "seniors", "clothing", "essentials", "hygiene"]
    },
    {
      name: "Foster Care & Youth Transition Grants",
      priority: "HIGH",
      focus: "Independent living, workforce readiness, education support",
      awardMin: 25000,
      awardMax: 100000,
      useFor: ["Workforce-ready clothing", "Life-skills & employment readiness support", "Transitional guidance programming"],
      bestFunders: ["State agencies", "Federal grants", "National foundations"],
      keywords: ["transition-age youth", "post-foster care outcomes", "equity-driven intervention", "workforce", "life skills", "employment"]
    }
  ],
  geographic: "Georgia",
  orgType: "501(c)(3) nonprofit"
};

const grantData = $input.first().json;
return [{ json: { ...grantData, eligibilityCriteria } }];

const item = $input.first();
const aiResponse = item.json;

let analysis = null;
let parseError = null;

// Extract JSON from AI response
try {
  let responseText = '';

  if (aiResponse.text) {
    responseText = aiResponse.text;
  } else if (aiResponse.message?.content) {
    responseText = aiResponse.message.content;
  } else if (aiResponse.output && Array.isArray(aiResponse.output)) {
    responseText = aiResponse.output[0]?.content?.[0]?.text || '';
  } else if (typeof aiResponse === 'string') {
    responseText = aiResponse;
  }

  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) analysis = JSON.parse(jsonMatch[0]);
} catch (e) {
  parseError = e.message;
}

const originalData = $('Load Eligibility Criteria3').first().json;
const scannerData = originalData.originalGrantData || {};

if (!analysis) {
  return [{
    json: {
      success: false,
      error: 'Failed to parse AI response',
      parseError,
      sourceUrl: originalData.sourceUrl,
      sourceType: originalData.sourceType
    }
  }];
}

// ===== BUILD RESULT =====
const score = (analysis.overallScore || 'YELLOW').toLowerCase(); // convert to lowercase to match enum
const allowedScores = ['green', 'yellow', 'red'];
const screening_result = allowedScores.includes(score) ? score : 'yellow'; // fallback if unexpected

const result = {
  success: true,
  data: {
    // analysis: analysis,
    id: analysis.grantid,
    org_id: analysis.org_id,
    title: analysis.grantTitle,
    stage: "screening",
    funder_name: analysis.agency || scannerData.agency || 'Unknown',
    amount: analysis.fundingRange || scannerData.awardRange || null,
    deadline: analysis.deadline || scannerData.deadline,

    eligibility: {
      score: score.toUpperCase(),
      confidence: analysis.confidence || 50,
      indicator: {
        green: '🟢',
        yellow: '🟡',
        red: '🔴'
      }[score] || '⚪'
    },

    screening_score: analysis.confidence, // enum-safe value

    screening_notes: analysis.summary || 'Unable to determine eligibility',
    categories: analysis.categories || {},
    concerns: analysis.concerns || [],
    recommendations: analysis.recommendations || [],

    source: {
      url: originalData.sourceUrl,
      type: originalData.sourceType,
      analyzedAt: new Date().toISOString()
    },

    organization: originalData.eligibilityCriteria.geographic || {}
  }
};
return result;

return items.map(item => {
    const grant = item.json;
